@RestController
class ProductController {

    private final JdbcTemplate jdbcTemplate;

    @Autowired
    public ProductController(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
    }

    @GetMapping("/api/products/search")
    public ResponseEntity<List<Product>> searchProducts(@RequestParam("name") String name) {
        String sql = "SELECT id, name, price FROM products WHERE LOWER(name) LIKE LOWER(?)";
        String likePattern = "%" + name + "%";

        try {
            List<Product> products = jdbcTemplate.query(sql, new Object[]{likePattern}, new ProductRowMapper());
            return ResponseEntity.ok(products);
        } catch (DataAccessException e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    static class ProductRowMapper implements RowMapper<Product> {
        @Override
        public Product mapRow(ResultSet rs, int rowNum) throws SQLException {
            Product product = new Product();
            product.setId(rs.getLong("id"));
            product.setName(rs.getString("name"));
            product.setPrice(rs.getBigDecimal("price"));
            return product;
        }
    }
}

